// ============================================================================
// PER-ENTITY BUNDLE (loaded from generated/entities/<id>.json)
// ============================================================================

/**
 * Per-entity JSON bundle generated by build-data.mjs.
 * Contains all the data needed to render a single entity's wiki page,
 * avoiding the need to load the full database.json.
 */
export interface EntityBundle {
  entity?: Record<string, unknown>;
  page?: Page;
  backlinks?: BacklinkEntry[];
  relatedGraph?: RelatedGraphEntry[];
  citationQuotes?: Array<Record<string, unknown>>;
  pageReferences?: SerializedPageReferences;
  pageResources?: string[];
}

const GENERATED_ENTITY_DIR = path.resolve(process.cwd(), "src/data/generated/entities");

/** In-memory cache for per-entity bundles (Map<entityId, bundle | null>) */
const _entityBundleCache = new Map<string, EntityBundle | null>();

/**
 * Load a per-entity JSON bundle from generated/entities/<id>.json.
 * Returns null if the file doesn't exist (entity may not have been bundled).
 * Results are cached in memory for the lifetime of the process.
 */
export function getEntityBundle(entityId: string): EntityBundle | null {
  if (!entityId) return null;
  const slug = resolveIdWithoutRegistry(entityId);

  if (_entityBundleCache.has(slug)) {
    return _entityBundleCache.get(slug)!;
  }

  // Sanitize slug for filename (some IDs contain path separators)
  const safeFilename = slug.replace(/\//g, "__");
  const bundlePath = path.join(GENERATED_ENTITY_DIR, `${safeFilename}.json`);
  try {
    const raw = fs.readFileSync(bundlePath, "utf-8");
    const bundle = JSON.parse(raw) as EntityBundle;
    _entityBundleCache.set(slug, bundle);
    return bundle;
  } catch {
    _entityBundleCache.set(slug, null);
    return null;
  }
}

/**
 * Resolve a numeric ID (E35) to slug without loading the full database.
 * Falls back to the full registry if needed, but tries the lightweight approach first.
 */
function resolveIdWithoutRegistry(id: string): string {
  if (!/^E\d+$/.test(id)) return id;
  // Must use the registry — load it from the database
  const registry = getIdRegistry();
  return registry.byNumericId[id] || id;
}

// ============================================================================
// DATABASE LOADING
// ============================================================================

/** Union of fully-typed entities and generic (unknown-type) entities */
export type AnyEntity = TypedEntity | GenericEntity;

let _database: TableBaseShape | null = null;
let _typedEntities: AnyEntity[] | null = null;

export function getTableBase(): TableBaseShape {
  if (_database) return _database;

  const dbPath = path.join(LOCAL_DATA_DIR, "database.json");

  try {
    const raw = fs.readFileSync(dbPath, "utf-8");
    _database = JSON.parse(raw) as TableBaseShape;
  } catch (err) {
    throw new Error(
      `Failed to load database from ${dbPath}: ${err instanceof Error ? err.message : err}. ` +
      `Run "pnpm prebuild" first.`
    );
  }
  return _database;
}

/** @deprecated Use getTableBase() */
export const getDatabase = getTableBase;

/** Get all typed entities from the database */
export function getTypedEntities(): AnyEntity[] {
  if (_typedEntities) return _typedEntities;

  const db = getDatabase();

  if (!db.typedEntities || db.typedEntities.length === 0) {
    throw new Error(
      'database.json is missing typedEntities. ' +
      'Run "pnpm --filter longterm-next prebuild" to rebuild.'
    );
  }

  const entities: AnyEntity[] = [];
  const isDev = process.env.NODE_ENV === "development";

  for (const raw of db.typedEntities) {
    const result = TypedEntitySchema.safeParse(raw);
    if (result.success) {
      entities.push(result.data);
    } else {
      // Unknown entity types — keep all fields as-is.
      // Don't re-parse through GenericEntitySchema as Zod would strip extra keys
      // like content, currentAssessment, ratings, causeEffectGraph.
      if (isDev) {
        const id = (raw as Record<string, unknown>).id;
        const type = (raw as Record<string, unknown>).entityType as string;
        console.warn(
          `[entity-validation] ${id} (${type}): ${result.error.issues.map(i => i.message).join(", ")}`
        );
      }
      entities.push(raw as unknown as GenericEntity);
    }
  }

  _typedEntities = entities;
  return _typedEntities;
}

