// ============================================================================
// ID RESOLUTION
// ============================================================================

/**
 * Resolve an ID that may be numeric (E35) or a slug (deepmind) to its slug form.
 * Returns the original ID if it's already a slug or not found in the registry.
 */
export function resolveId(id: string): string {
  if (/^E\d+$/.test(id)) {
    const registry = getIdRegistry();
    return registry.byNumericId[id] || id;
  }
  return id;
}

export function getIdRegistry(): IdRegistryMaps {
  return getDatabase().idRegistry;
}

// ============================================================================
// LOOKUP INDEXES (built lazily)
// ============================================================================

let _typedEntityIndex: Map<string, AnyEntity> | null = null;
let _resourceIndex: Map<string, Resource> | null = null;
let _stableIdIndex: Map<string, Resource> | null = null;
let _publicationIndex: Map<string, Publication> | null = null;
let _expertIndex: Map<string, Expert> | null = null;
let _orgIndex: Map<string, Organization> | null = null;
let _pageIndex: Map<string, Page> | null = null;

function typedEntityIndex() {
  if (!_typedEntityIndex) {
    _typedEntityIndex = new Map(getTypedEntities().map(e => [e.id, e]));
  }
  return _typedEntityIndex;
}

function resourceIndex() {
  if (!_resourceIndex) {
    const db = getDatabase();
    const resources = db.resources || [];
    _resourceIndex = new Map();
    _stableIdIndex = new Map();
    for (const r of resources) {
      _resourceIndex.set(r.id, r);
      if (r.stable_id) {
        const existing = _stableIdIndex.get(r.stable_id);
        if (existing && existing.id !== r.id) {
          throw new Error(
            `Duplicate resource stable_id "${r.stable_id}" for "${existing.id}" and "${r.id}"`
          );
        }
        _stableIdIndex.set(r.stable_id, r);
      }
    }
  }
  return _resourceIndex;
}

function stableIdIndex() {
  if (!_stableIdIndex) resourceIndex(); // builds both indexes
  return _stableIdIndex!;
}

function publicationIndex() {
  if (!_publicationIndex) {
    const db = getDatabase();
    _publicationIndex = new Map(
      (db.publications || []).map((p) => [p.id, p])
    );
  }
  return _publicationIndex;
}

function expertIndex() {
  if (!_expertIndex) {
    const db = getDatabase();
    _expertIndex = new Map((db.experts || []).map((e) => [e.id, e]));
  }
  return _expertIndex;
}

function orgIndex() {
  if (!_orgIndex) {
    const db = getDatabase();
    _orgIndex = new Map((db.organizations || []).map((o) => [o.id, o]));
  }
  return _orgIndex;
}

function pageIndex() {
  if (!_pageIndex) {
    const db = getDatabase();
    _pageIndex = new Map((db.pages || []).map((p) => [p.id, p]));
  }
  return _pageIndex;
}

// ============================================================================
// LOOKUP FUNCTIONS
// ============================================================================

/** Get a typed entity by ID — accepts numeric (E35) or slug (deepmind) */
export function getTypedEntityById(id: string): AnyEntity | undefined {
  return typedEntityIndex().get(resolveId(id));
}

/** @deprecated Use getTypedEntityById for new code */
export function getEntityById(id: string): Entity | undefined {
  // Return typed entity cast to the old Entity interface for backward compat
  const typed = typedEntityIndex().get(resolveId(id));
  if (!typed) return undefined;
  return {
    id: typed.id,
    type: typed.entityType,
    title: typed.title,
    description: typed.description,
    tags: typed.tags,
    relatedEntries: typed.relatedEntries,
    sources: typed.sources,
    lastUpdated: typed.lastUpdated,
    website: typed.website,
    customFields: typed.customFields,
    // Type-specific fields (spread them for backward compat)
    ...(isRisk(typed) ? {
      severity: typed.severity,
      likelihood: typed.likelihood,
      timeframe: typed.timeframe,
      maturity: typed.maturity,
    } : {}),
  };
}

export function getResourceById(id: string): Resource | undefined {
  return resourceIndex().get(id);
}

/**
 * Resolve a resource by hash ID or stable_id.
 * Tries hash ID first (16-char hex), then stable_id (10-char alphanumeric).
 */
export function resolveResource(id: string): Resource | undefined {
  return resourceIndex().get(id) ?? stableIdIndex().get(id);
}

/** Get all resources */
export function getAllResources(): Resource[] {
  const db = getDatabase();
  return db.resources ?? [];
}

/** Get resource IDs for a page (computed at build time from inline <R>, cited_by, URL matching) */
export function getResourcesForPage(pageId: string): string[] {
  const slug = resolveId(pageId);
  // Try per-entity bundle first (avoids loading full database.json)
  const bundle = getEntityBundle(slug);
  if (bundle?.pageResources) return bundle.pageResources;
  const db = getDatabase();
  return db.pageResources?.[slug] ?? [];
}

/** Get page IDs that cite a given resource (reverse lookup of pageResources) */
export function getPagesForResource(resourceId: string): string[] {
  const db = getDatabase();
  const pr = db.pageResources ?? {};
  const pages: string[] = [];
  for (const [pageId, ids] of Object.entries(pr)) {
    if ((ids as string[]).includes(resourceId)) {
      pages.push(pageId);
    }
  }
  return pages;
}

/** Get DB-driven reference data for a page (for the reference preprocessor) */
export function getPageReferences(pageId: string): SerializedPageReferences | null {
  const slug = resolveId(pageId);
  // Try per-entity bundle first
  const bundle = getEntityBundle(slug);
  if (bundle?.pageReferences) return bundle.pageReferences;
  const db = getDatabase();
  return db.pageReferenceIndex?.[slug] ?? null;
}

export function getPublicationById(id: string): Publication | undefined {
  return publicationIndex().get(id);
}

/** Get all publications */
export function getAllPublications(): Publication[] {
  const db = getDatabase();
  return db.publications ?? [];
}

/** Get all literature papers (from literature.yaml loaded at build time). */
export function getLiteraturePapers(): LiteraturePaper[] {
  const db = getDatabase();
  if (!db.literature?.categories) return [];
  return db.literature.categories.flatMap((c) => c.papers ?? []);
}

/** Get resources that belong to a publication */
export function getResourcesForPublication(publicationId: string): Resource[] {
  return getAllResources().filter((r) => r.publication_id === publicationId);
}

/** Get publications linked to a person entity (from people-resources.yaml) */
export function getPublicationsForPerson(
  personId: string,
): PersonPublicationEntry[] {
  const db = getDatabase();
  const entry = (db.peopleResources ?? []).find(
    (pr) => pr.personId === personId,
  );
  return entry?.publications ?? [];
}

export function getExpertById(id: string): Expert | undefined {
  return expertIndex().get(id);
}

export function getAllExperts(): Expert[] {
  return getDatabase().experts ?? [];
}

export function getOrganizationById(id: string): Organization | undefined {
  return orgIndex().get(id);
}

export function getPageById(id: string): Page | undefined {
  const slug = resolveId(id);
  // Try per-entity bundle first (avoids loading full database for single-page lookups)
  const bundle = getEntityBundle(slug);
  if (bundle?.page) return bundle.page;
  return pageIndex().get(slug);
}

export function getAllPages(): Page[] {
  return getDatabase().pages || [];
}

// ============================================================================
// RESOURCE HELPERS
// ============================================================================

export function getResourceCredibility(
  resource: Resource
): number | undefined {
  if (resource.credibility_override !== undefined) return resource.credibility_override;
  if (resource.publication_id) {
    const pub = getPublicationById(resource.publication_id);
    return pub?.credibility;
  }
  return undefined;
}

export function getResourcePublication(
  resource: Resource
): Publication | undefined {
  if (resource.publication_id) {
    return getPublicationById(resource.publication_id);
  }
  return undefined;
}

// ============================================================================
// PERSON NAME LOOKUP
// ============================================================================

let _personNameIndex: Map<string, string> | null = null;

/**
 * Build a lazily-cached index of person name → entity ID.
 * Normalizes to lowercase for case-insensitive matching.
 */
function personNameIndex(): Map<string, string> {
  if (!_personNameIndex) {
    _personNameIndex = new Map();
    for (const entity of getTypedEntities()) {
      if (isPerson(entity)) {
        _personNameIndex.set(entity.title.toLowerCase(), entity.id);
      }
    }
  }
  return _personNameIndex;
}

/**
 * Find a person entity by name (case-insensitive).
 * Returns the entity ID if a matching person is found, undefined otherwise.
 */
export function findPersonByName(name: string): string | undefined {
  return personNameIndex().get(name.toLowerCase());
}

